private _listens(type: string): boolean {
    return (
      (this._listeners[type] && this._listeners[type].length > 0) || (this._onceListeners[type] && this._onceListeners[type].length > 0)
    )
  }

function addEventListener(type: string, listener: Listener, registry: ListenerRegistry) {
  registry[type] = registry[type] || []
  if (registry[type].indexOf(listener) < 0) {
    // Does not exist
    registry[type].push(listener)
  }
}

function removeEventListener(type: string, listener: Listener, registry: ListenerRegistry) {
  if (registry[type]) {
    const index = registry[type].indexOf(listener)
    if (index >= 0) {
      registry[type].splice(index, 1)
    }
  }
}

setStyle(style: GraphStyleSpecification) {
    this._style = parseGraphStyle(style)
    const layer = this._deck.props.layers[0]
    if (layer) {
      const newLayer = layer.clone({
        graphStyle: this._style,
      })
      this._deck.setProps({
        layers: [newLayer],
      })
    }
  }

toJSON(): BundlingSettingsJSON {
    const ret: BundlingSettingsJSON = {}
    if (this.capacityOverflowCoefficient != BundlingSettings.DefaultCapacityOverflowCoefficientMultiplier)
      ret.capacityOverflowCoefficient = this.capacityOverflowCoefficient
    if (this.RotateBundles) ret.RotateBundles

IsEmpty(): boolean {
    return this.TightObstacles == null || this.TightObstacles.size === 0
  }

*GetEnumerator(): IterableIterator<T> {
    for (let i = 1; i <= this.heapSize; i++) {
      yield this.A[i].v
    }
  }

public Peek(t: {priority: number}): T {
    if (this.count === 0) {
      t.priority = 0
      return
    }

    t.priority = this.A[1].priority
    return this.A[1].v
  }

toString(): string {
    const sb: StringBuilder = new StringBuilder()
    for (const i of this.A) {
      sb.Append(i + ',')
    }

    return sb.ToString()
  }

constructor(index: number, priority: number, v: T) {
    this.indexToA = index
    this.priority = priority
    this.v = v
  }
